import PremiumCard from "~/components/status/PremiumCard";
import { useNavigate, useParams } from "react-router-dom";
import { useLocalStorage } from "~/hooks/useLocalStorage";
import { WATERMARK_MENUS } from "~/constants/menus";
import ToggleTheme from "~/components/toggleTheme";
import InlineStack from "~/components/inlineStack";
import Upgrade from "~/components/status/Upgrade";
import BlockStack from "~/components/blockStack";
import IconButton from "~/components/iconButton";
import TextComponent from "~/components/text";
import Sidebar from "~/components/sidebar";
import Layout from "~/components/layout";
import Topbar from "~/components/topbar";
import { __ } from "@wordpress/i18n";
/* <fs_premium_only> */
import useWatermarkActions from "./hooks__premium_only/useWatermarkActions";
import Preview from "./components__premium_only/Preview";
import Filter from "./components__premium_only/Filter";
import Image from "./pages__premium_only/image/Image";
import Apply from "./components__premium_only/Apply";
import Text from "./pages__premium_only/text/Text";
import Tile from "./components__premium_only/Tile";
import { useEffect } from "@wordpress/element";
import useSettings from "~/hooks/useSettings";
import Disabled from "~/components/disabled";
import Button from "~/components/button";
/* </fs_premium_only> */

const Watermark = () => {
    const [theme, setTheme] = useLocalStorage<"light" | "dark">(
        "pnpnm-theme-status",
        "light",
    );

    const { menuKey } = useParams();

    const navigate = useNavigate();

    /* <fs_premium_only> */
    const { data, isDataChanged, setSettings, saveSettings } = useSettings();

    const { resetSettings } = useWatermarkActions();

    const enabled = data?.watermark?.enabled ?? false;

    useEffect(() => {
        if (data?.tools?.autoSave && isDataChanged) {
            saveSettings();
        }
    }, [data?.tools?.autoSave, isDataChanged]);

    useEffect(() => {
        if (menuKey) {
            setSettings(
                "watermark.type",
                (menuKey as "text" | "image") ?? "text",
            );
        }
    }, [menuKey]);
    /* </fs_premium_only> */

    const handleMenuClick = (key: (typeof WATERMARK_MENUS)[number]["key"]) => {
        navigate(`/watermark/${key}`);
    };

    const topbarTitle = (
        <InlineStack gap={10}>
            <IconButton
                variant="secondary"
                rounded="md"
                color="primary"
                name={WATERMARK_MENUS?.find(({ key }) => key === menuKey)?.icon}
            />

            <TextComponent color="primary" size="xl" weight="medium">
                {WATERMARK_MENUS?.find(({ key }) => key === menuKey)?.title}
            </TextComponent>
        </InlineStack>
    );

    const themeButton = <ToggleTheme theme={theme} setTheme={setTheme} />;

    const topbarRightContents = [themeButton];

    /* <fs_premium_only> */
    if (pnpnm?.isPro) {
        const reset = (
            <Button
                variant="error"
                startIcon="refresh"
                statusProps={{
                    default: true,
                    isPro: true,
                }}
                onClick={() => {
                    if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

                    resetSettings();
                }}
            >
                {__("Reset", "ninja-media")}
            </Button>
        );

        const enableButton = (
            <Button
                id="enableWatermark"
                variant={enabled ? "secondary" : "primary"}
                startIcon={enabled ? "toggle_off" : "toggle_on"}
                statusProps={{
                    default: true,
                    isPro: true,
                }}
                onClick={() => {
                    if (!pnpnm?.isPro) return;

                    setSettings("watermark.enabled", !enabled);
                }}
            >
                {enabled
                    ? __("Disable", "ninja-media")
                    : __("Enable", "ninja-media")}
            </Button>
        );

        const save = (
            <Button
                variant="primary"
                startIcon="check"
                statusProps={{
                    default: true,
                    isPro: true,
                }}
                onClick={() => {
                    if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

                    saveSettings();
                }}
                disabled={!isDataChanged || !data?.watermark?.enabled}
            >
                {__("Save Settings", "ninja-media")}
            </Button>
        );

        topbarRightContents.push(reset, enableButton, save);
    }

    const renderPage = () => {
        const pageComponents: Record<string, JSX.Element> = {
            text: <Text />,
            image: <Image />,
        };

        return pageComponents[menuKey!] || <Text />;
    };
    /* </fs_premium_only> */

    return (
        <Layout>
            <Sidebar minWidth={300}>
                <Sidebar.Menu>
                    {WATERMARK_MENUS?.map(({ key, title, icon }, index) => (
                        <Sidebar.Item
                            key={key ?? index}
                            title={title}
                            icon={icon}
                            active={key === menuKey}
                            onClick={() => handleMenuClick(key)}
                        />
                    ))}
                </Sidebar.Menu>

                {!pnpnm.isPro && (
                    <BlockStack
                        align="center"
                        inlineAlign="center"
                        className="h-full"
                    >
                        <PremiumCard />
                    </BlockStack>
                )}

                <Sidebar.Bottom>
                    <Sidebar.HelpCenter />

                    {!pnpnm.isPro && <Sidebar.UpgradePro />}
                </Sidebar.Bottom>
            </Sidebar>

            <Layout.Wrapper>
                <Topbar
                    leftContents={[topbarTitle]}
                    rightContents={topbarRightContents}
                />

                <Layout.Content>
                    {!pnpnm?.isPro && <Upgrade />}

                    {/* <fs_premium_only> */}
                    <Disabled
                        depend={!enabled}
                        dependOn="enableWatermark"
                        dependOnExact
                        style={{
                            display: "flex",
                            flexDirection: "row",
                            alignItems: "flex-start",
                            flexWrap: "nowrap",
                            gap: 20,
                        }}
                    >
                        <BlockStack
                            gap={20}
                            style={{
                                width: "50%",
                            }}
                        >
                            {renderPage()}

                            <Tile />

                            <Filter />

                            <Apply />
                        </BlockStack>

                        <Preview />
                    </Disabled>
                    {/* </fs_premium_only> */}
                </Layout.Content>
            </Layout.Wrapper>
        </Layout>
    );
};

export default Watermark;
