import PageContainer from "~/components/pageContainer";
import SettingsField from "~/components/settingsField";
import Description from "~/components/description";
import ButtonGroup from "~/components/buttonGroup";
import InlineStack from "~/components/inlineStack";
import SelectBox from "~/components/selectBox";
import useSettings from "~/hooks/useSettings";
import Switcher from "~/components/switcher";
import Disabled from "~/components/disabled";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";
import Text from "~/components/text";
import Condition from "./Condition";

const Filter = () => {
    const { data, setSettings } = useSettings();

    const { applyOn, allowedExtensions, allowAll, except, jpegQuality } =
        data?.watermark || {};

    return (
        <PageContainer>
            <SettingsField title={__("Apply On", "ninja-media")} gap={10}>
                <ButtonGroup
                    background="extralight"
                    buttons={APPLY_ON_BUTTONS}
                    selectedKey={applyOn || "all"}
                    onChange={(value) =>
                        setSettings(
                            "watermark.applyOn",
                            value as (typeof APPLY_ON_BUTTONS)[number]["key"],
                        )
                    }
                />

                <Description
                    text={__(
                        "Choose the image sizes that the watermark should be applied to.",
                        "ninja-media",
                    )}
                />
            </SettingsField>

            <SettingsField
                title={__("Allowed file types", "ninja-media")}
                description={__(
                    "Select the file types that the watermark should be applied to.",
                    "ninja-media",
                )}
                secondaryAction={
                    <SelectBox
                        multiple
                        size="small"
                        options={MIME_OPTIONS}
                        value={allowedExtensions}
                        onChange={(value) =>
                            setSettings("watermark.allowedExtensions", value)
                        }
                    />
                }
            >
                <SettingsField.SubField
                    action={
                        <Switcher
                            id="watermarkAllowAll"
                            title={__("Allow all types", "ninja-media")}
                            checked={allowAll}
                            onChange={() =>
                                setSettings("watermark.allowAll", !allowAll)
                            }
                        />
                    }
                >
                    <Disabled
                        gap={10}
                        depend={!allowAll}
                        dependOn="watermarkAllowAll"
                    >
                        <InlineStack gap={10} wrap={false}>
                            <Text weight="medium">
                                {__("Except", "ninja-media")}
                            </Text>

                            <SelectBox
                                multiple
                                size="small"
                                options={MIME_OPTIONS}
                                value={except}
                                onChange={(value) =>
                                    setSettings("watermark.except", value)
                                }
                            />
                        </InlineStack>

                        <Description
                            text={__(
                                "Select the file types that should be excluded from the watermark.",
                                "ninja-media",
                            )}
                        />
                    </Disabled>
                </SettingsField.SubField>
            </SettingsField>

            <Condition />

            <SettingsField
                title={__("JPEG / WebP quality", "ninja-media")}
                description={__(
                    "Output compression quality for JPEG and WebP formats (1–100). Higher = better quality, larger file.",
                    "ninja-media",
                )}
                secondaryAction={
                    <Input
                        type="number"
                        size="small"
                        suffix="%"
                        fullWidth={false}
                        value={jpegQuality ?? ""}
                        onChange={(value) =>
                            setSettings("watermark.jpegQuality", Number(value))
                        }
                    />
                }
            />
        </PageContainer>
    );
};

export default Filter;

export const APPLY_ON_BUTTONS: {
    key: "all" | "thumbnail" | "medium" | "large" | "full";
    title: string;
    startIcon: string;
}[] = [
    {
        key: "all",
        title: __("All Sizes", "ninja-media"),
        startIcon: "grid_view",
    },
    {
        key: "thumbnail",
        title: __("Thumbnail", "ninja-media"),
        startIcon: "photo_size_select_small",
    },
    {
        key: "medium",
        title: __("Medium", "ninja-media"),
        startIcon: "photo_size_select_small",
    },
    {
        key: "large",
        title: __("Large", "ninja-media"),
        startIcon: "photo_size_select_large",
    },
    { key: "full", title: __("Full Size", "ninja-media"), startIcon: "image" },
];

export const MIME_OPTIONS: { name: string; value: string }[] = [
    { name: "JPEG", value: "image/jpeg" },
    { name: "PNG", value: "image/png" },
    { name: "GIF", value: "image/gif" },
    { name: "WebP", value: "image/webp" },
];
