import Fonts from "../../components__premium_only/Fonts";
import SettingsField from "~/components/settingsField";
import PageContainer from "~/components/pageContainer";
import ColorPicker from "~/components/colorPicker";
import InlineStack from "~/components/inlineStack";
import Description from "~/components/description";
import BlockStack from "~/components/blockStack";
import SelectBox from "~/components/selectBox";
import useSettings from "~/hooks/useSettings";
import TextComponent from "~/components/text";
import Switcher from "~/components/switcher";
import Divider from "~/components/divider";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";

const Text = () => {
    const { data, setSettings } = useSettings();

    const { text } = data?.watermark || {};

    const { content, fontSize, fontFamily, rotation, color, bold, italic } =
        text || {};

    return (
        <PageContainer>
            <SettingsField title={__("Title", "ninja-media")}>
                <BlockStack gap={10}>
                    <Input
                        size="small"
                        value={content ?? ""}
                        onChange={(value) =>
                            setSettings("watermark.text.content", String(value))
                        }
                    />

                    <Description
                        text={__(
                            "Enter the title for the watermark text.",
                            "ninja-media",
                        )}
                    />
                </BlockStack>

                <InlineStack gap={10} wrap={false}>
                    <BlockStack gap={10} className="flex-1">
                        <TextComponent size="sm" weight="medium">
                            {__("Font Size", "ninja-media")}
                        </TextComponent>

                        <Input
                            type="number"
                            size="small"
                            suffix="px"
                            value={fontSize ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.text.fontSize",
                                    Number(value),
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <TextComponent size="sm" weight="medium">
                            {__("Font Family", "ninja-media")}
                        </TextComponent>

                        <SelectBox
                            size="small"
                            options={FONT_OPTIONS}
                            value={[fontFamily || ""]}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.text.fontFamily",
                                    value[0],
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <TextComponent size="sm" weight="medium">
                            {__("Rotation", "ninja-media")}
                        </TextComponent>

                        <Input
                            type="number"
                            size="small"
                            suffix="°"
                            value={rotation ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.text.rotation",
                                    Number(value),
                                )
                            }
                        />
                    </BlockStack>
                </InlineStack>

                <InlineStack
                    gap={20}
                    wrap={false}
                    align="between"
                    blockAlign="end"
                >
                    <BlockStack gap={10}>
                        <TextComponent size="sm" weight="medium">
                            {__("Color", "ninja-media")}
                        </TextComponent>

                        <ColorPicker
                            defaultColor="#2271B1"
                            selectedColor={color ?? "#2271B1"}
                            onChange={(color) =>
                                setSettings("watermark.text.color", color)
                            }
                        />
                    </BlockStack>

                    <InlineStack gap={10}>
                        <Switcher
                            title={__("Bold", "ninja-media")}
                            titleSize="sm"
                            checked={bold}
                            onChange={(value) =>
                                setSettings("watermark.text.bold", value)
                            }
                        />

                        <Divider variant="vertical" height="20px" />

                        <Switcher
                            title={__("Italic", "ninja-media")}
                            titleSize="sm"
                            checked={italic}
                            onChange={(value) =>
                                setSettings("watermark.text.italic", value)
                            }
                        />
                    </InlineStack>
                </InlineStack>
            </SettingsField>

            <Fonts />
        </PageContainer>
    );
};

export default Text;

export const FONT_OPTIONS: { name: string; value: string }[] = [
    { name: __("Sans Serif (Arial-like)", "ninja-media"), value: "Sans Serif" },
    { name: __("Serif (Times-like)", "ninja-media"), value: "Serif" },
    { name: __("Monospace (Courier-like)", "ninja-media"), value: "Monospace" },
    { name: __("DejaVu Sans (Unicode)", "ninja-media"), value: "DejaVu Sans" },
];
