import { useCallback, useRef, useState } from "@wordpress/element";
import SettingsField from "~/components/settingsField";
import Description from "~/components/description";
import InlineStack from "~/components/inlineStack";
import BlockStack from "~/components/blockStack";
import useSettings from "~/hooks/useSettings";
import { __, sprintf } from "@wordpress/i18n";
import Switcher from "~/components/switcher";
import Button from "~/components/button";
import Input from "~/components/input";
import Text from "~/components/text";
import Icon from "~/components/icon";
import {
    useDeleteWatermarkFontMutation,
    useGetWatermarkFontsQuery,
    useUploadWatermarkFontMutation,
} from "~/redux/api/watermark__premium_only";

const Fonts = () => {
    const { data, setSettings } = useSettings();
    const { data: fontsData } = useGetWatermarkFontsQuery();
    const [uploadFont, { isLoading: isUploading }] =
        useUploadWatermarkFontMutation();
    const [deleteFont, { isLoading: isDeleting }] =
        useDeleteWatermarkFontMutation();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [uploadError, setUploadError] = useState("");
    const [uploadSuccess, setUploadSuccess] = useState("");

    const { enabled, name } = data?.watermark?.customFonts || {};

    const handleFontFileChange = useCallback(
        (e: React.ChangeEvent<HTMLInputElement>) => {
            const file = e.target.files?.[0];

            if (!file) return;

            if (!name?.trim()) {
                const base = file.name
                    .replace(/\.[^.]+$/, "")
                    .replace(/[-_]/g, " ");
                setSettings(
                    "watermark.customFonts.name",
                    base.charAt(0).toUpperCase() + base.slice(1),
                );
            }
        },
        [setSettings, name],
    );

    const handleFontUpload = useCallback(async () => {
        if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

        const file = fileInputRef.current?.files?.[0];

        if (!file) {
            setUploadError(
                __("Please select a font file first.", "ninja-media"),
            );
            return;
        }

        setUploadError("");
        setUploadSuccess("");

        const formData = new FormData();
        formData.append("font", file);
        formData.append(
            "name",
            name?.trim() || file.name.replace(/\.[^.]+$/, ""),
        );

        try {
            const result = await uploadFont(formData).unwrap();

            setUploadSuccess(
                sprintf(
                    __('"%s" uploaded successfully.', "ninja-media"),
                    result?.data?.font.name ?? "",
                ),
            );

            setSettings("watermark.customFonts.name", "");

            if (fileInputRef.current) fileInputRef.current.value = "";
        } catch (err: unknown) {
            const msg =
                (err as { data?: { message?: string } })?.data?.message ??
                __("Upload failed. Please try again.", "ninja-media");

            setUploadError(msg);
        }
    }, [uploadFont, name, setSettings]);

    const handleFontDelete = useCallback(
        async (slug: string) => {
            if (!window.confirm(__("Remove this custom font?", "ninja-media")))
                return;

            try {
                await deleteFont({ slug }).unwrap();
            } catch {}
        },
        [deleteFont],
    );

    return (
        <SettingsField
            description={__(
                "Enable custom font for the watermark text.",
                "ninja-media",
            )}
            action={
                <Switcher
                    id="customFonts"
                    title={__("Custom Fonts", "ninja-media")}
                    checked={enabled}
                    onChange={() =>
                        setSettings("watermark.customFonts.enabled", !enabled)
                    }
                />
            }
        >
            <SettingsField.SubField depend={!enabled} dependOn="customFonts">
                <InlineStack gap={10} wrap={false}>
                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Font Name", "ninja-media")}
                        </Text>

                        <Input
                            size="small"
                            value={name ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.customFonts.name",
                                    String(value),
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10}>
                        <Text size="sm" weight="medium">
                            {__(
                                "Font file (.ttf / .otf / .woff / .woff2)",
                                "ninja-media",
                            )}
                        </Text>

                        <InlineStack gap={10}>
                            <input
                                ref={fileInputRef}
                                type="file"
                                accept=".ttf,.otf,.woff,.woff2"
                                style={{ display: "none" }}
                                onChange={handleFontFileChange}
                            />

                            <Button
                                variant="outlined"
                                size="small"
                                startIcon="upload"
                                onClick={() => fileInputRef.current?.click()}
                            >
                                {fileInputRef.current?.files?.[0]?.name ??
                                    __("Choose file", "ninja-media")}
                            </Button>

                            <Button
                                variant="primary"
                                size="small"
                                startIcon="add"
                                onClick={handleFontUpload}
                                loading={isUploading}
                            >
                                {__("Add Font", "ninja-media")}
                            </Button>
                        </InlineStack>
                    </BlockStack>
                </InlineStack>

                {uploadError && (
                    <Text color="error" size="sm">
                        {uploadError}
                    </Text>
                )}

                {uploadSuccess && (
                    <Text color="primary" size="sm">
                        {uploadSuccess}
                    </Text>
                )}

                {(fontsData?.data?.custom ?? []).length > 0 && (
                    <BlockStack gap={10}>
                        <Text size="sm" weight="medium">
                            {__("Uploaded fonts", "ninja-media")}
                        </Text>

                        {(fontsData?.data?.custom ?? []).map((font, index) => (
                            <InlineStack
                                key={font?.slug ?? index}
                                gap={8}
                                align="between"
                                blockAlign="center"
                                style={{
                                    padding: "6px 10px",
                                    background: "#fff",
                                    borderRadius: "6px",
                                    border: "1px solid #e5e7eb",
                                }}
                            >
                                <InlineStack gap={10} blockAlign="center">
                                    <Icon
                                        name="text_fields"
                                        color="descgray"
                                        fontSize="sm"
                                    />

                                    <BlockStack gap={5}>
                                        <Text size="sm" weight="medium">
                                            {font?.name}
                                        </Text>

                                        <Text size="xs" color="descgray">
                                            {font?.file}
                                        </Text>
                                    </BlockStack>
                                </InlineStack>

                                <Button
                                    variant="outlined"
                                    size="extrasmall"
                                    startIcon="delete"
                                    disabled={isDeleting}
                                    onClick={() => handleFontDelete(font?.slug)}
                                >
                                    {__("Remove", "ninja-media")}
                                </Button>
                            </InlineStack>
                        ))}
                    </BlockStack>
                )}

                {(fontsData?.data?.custom ?? []).length === 0 && (
                    <Description
                        text={__(
                            "No custom fonts yet. Upload a TTF or OTF file above to add your own font.",
                            "ninja-media",
                        )}
                    />
                )}
            </SettingsField.SubField>
        </SettingsField>
    );
};

export default Fonts;
