import { useEffect, useState } from "@wordpress/element";

interface TileImageOptions {
    type: "image";
    imageUrl: string;
    sizePct: number;
    opacity: number;
    spacingX: number;
    spacingY: number;
    diagonal: boolean;
}

interface TileTextOptions {
    type: "text";
    content: string;
    fontSize: number;
    fontFamily: string;
    color: string;
    bold: boolean;
    italic: boolean;
    rotation: number;
    opacity: number;
    sizePct: number;
    spacingX: number;
    spacingY: number;
    diagonal: boolean;
}

type TileOptions = TileImageOptions | TileTextOptions;

const buildTileDataUrl = async (
    opts: TileOptions,
    containerW: number,
): Promise<string | null> => {
    let stampW = 0;
    let stampH = 0;
    let img: HTMLImageElement | null = null;

    if (opts.type === "image") {
        img = await new Promise<HTMLImageElement>((res, rej) => {
            const el = new Image();
            el.crossOrigin = "anonymous";
            el.onload = () => res(el);
            el.onerror = rej;
            el.src = opts.imageUrl;
        });
        const maxPx = (opts.sizePct / 100) * containerW;
        const ratio = img.naturalWidth / img.naturalHeight;
        if (ratio >= 1) {
            stampW = Math.min(maxPx, img.naturalWidth);
            stampH = stampW / ratio;
        } else {
            stampH = Math.min(maxPx, img.naturalHeight);
            stampW = stampH * ratio;
        }
    } else {
        const tmp = document.createElement("canvas");
        const tmpCtx = tmp.getContext("2d")!;
        const scaledFontSize = Math.max(
            8,
            Math.round((opts.fontSize * opts.sizePct) / 100),
        );
        const weight = opts.bold ? "bold" : "normal";
        const style = opts.italic ? "italic" : "normal";
        tmpCtx.font = `${style} ${weight} ${scaledFontSize}px ${opts.fontFamily}`;
        const metrics = tmpCtx.measureText(opts.content);
        stampW = Math.ceil(metrics.width) + 4;
        stampH = Math.ceil(scaledFontSize * 1.4);
    }

    if (stampW <= 0 || stampH <= 0) return null;

    const spacingX = Math.min(opts.spacingX, containerW * 0.5);
    const spacingY = Math.min(opts.spacingY, containerW * 0.5);

    const rotRad =
        opts.type === "text" && opts.rotation !== 0
            ? (-opts.rotation * Math.PI) / 180
            : 0;
    const needsPad = opts.type === "text" && opts.rotation !== 0;
    const diagLen = Math.ceil(Math.sqrt(stampW ** 2 + stampH ** 2));
    const sW = needsPad ? diagLen : Math.ceil(stampW);
    const sH = needsPad ? diagLen : Math.ceil(stampH);

    const stampCanvas = document.createElement("canvas");
    stampCanvas.width = sW;
    stampCanvas.height = sH;
    const sCtx = stampCanvas.getContext("2d")!;
    sCtx.globalAlpha = opts.opacity / 100;

    if (opts.type === "image" && img) {
        sCtx.drawImage(img, 0, 0, stampW, stampH);
    } else if (opts.type === "text") {
        const scaledFontSize = Math.max(
            8,
            Math.round((opts.fontSize * opts.sizePct) / 100),
        );
        const weight = opts.bold ? "bold" : "normal";
        const fStyle = opts.italic ? "italic" : "normal";
        sCtx.font = `${fStyle} ${weight} ${scaledFontSize}px ${opts.fontFamily}`;
        sCtx.fillStyle = opts.color;
        sCtx.textBaseline = "top";
        sCtx.save();
        sCtx.translate(sW / 2, sH / 2);
        sCtx.rotate(rotRad);
        sCtx.fillText(opts.content, -stampW / 2, -stampH / 2);
        sCtx.restore();
    }

    const cellW = Math.ceil(sW + spacingX);
    const cellH = Math.ceil(sH + spacingY);
    const tileCanvas = document.createElement("canvas");
    tileCanvas.width = cellW;
    tileCanvas.height = cellH;
    tileCanvas.getContext("2d")!.drawImage(stampCanvas, 0, 0);
    return tileCanvas.toDataURL("image/png");
};

export const useTilePreview = (
    opts: TileOptions | null,
    containerW: number,
    containerH: number,
): string | null => {
    const [dataUrl, setDataUrl] = useState<string | null>(null);

    useEffect(() => {
        if (!opts || containerW === 0) {
            setDataUrl(null);
            return;
        }
        if (opts.type === "text" && !opts.content.trim()) {
            setDataUrl(null);
            return;
        }
        if (opts.type === "image" && !opts.imageUrl) {
            setDataUrl(null);
            return;
        }

        let cancelled = false;

        buildTileDataUrl(opts, containerW)
            .then((url) => {
                if (!cancelled) setDataUrl(url);
            })
            .catch(() => {
                if (!cancelled) setDataUrl(null);
            });

        return () => {
            cancelled = true;
        };
    }, [JSON.stringify(opts), containerW, containerH]);

    return dataUrl;
};
