import { WatermarkPosition } from "~/types/watermark__premium_only/watermark";
import { useTilePreview } from "../hooks__premium_only/useTilePreview";
import { useEffect, useRef, useState } from "@wordpress/element";
import SettingsField from "~/components/settingsField";
import BlockStack from "~/components/blockStack";
import { __, sprintf } from "@wordpress/i18n";
import useSettings from "~/hooks/useSettings";
import { useParams } from "react-router-dom";
import Card from "~/components/card";
import Icon from "~/components/icon";
import Adjust from "./Adjust";

const Preview = () => {
    const { data } = useSettings();
    const [imageUrl, setImageUrl] = useState<string>("");

    const { menuKey } = useParams();

    const { type, text, image, position, size, opacity, edgeMargin, tile } =
        data?.watermark || {};

    const { content, fontSize, fontFamily, rotation, color, bold, italic } =
        text || {};

    const containerRef = useRef<HTMLDivElement>(null);
    const [containerSize, setContainerSize] = useState({ w: 0, h: 0 });

    useEffect(() => {
        const el = containerRef.current;
        if (!el) return;

        const ro = new ResizeObserver(([entry]) => {
            setContainerSize({
                w: Math.round(entry.contentRect.width),
                h: Math.round(entry.contentRect.height),
            });
        });

        ro.observe(el);
        return () => ro.disconnect();
    }, []);

    useEffect(() => {
        if (!image) {
            setImageUrl("");
            return;
        }

        const attachment = window.wp.media.attachment(image);

        attachment.fetch().then(() => {
            setImageUrl(attachment.get("url") || "");
        });
    }, [image]);

    const isTiled = !!tile?.enabled;
    const spacingX = tile?.spacingX ?? 20;
    const spacingY = tile?.spacingY ?? 20;
    const diagonal = tile?.diagonal ?? false;

    const resolvedContent = (content ?? "")
        .replace("{site_name}", "My Site")
        .replace("{year}", String(new Date().getFullYear()))
        .replace("{author}", "Admin")
        .replace("{filename}", "photo")
        .replace("{date}", new Date().toISOString().slice(0, 10));

    const tileOpts = isTiled
        ? type === "image" && imageUrl
            ? {
                  type: "image" as const,
                  imageUrl,
                  sizePct: size ?? 20,
                  opacity: opacity ?? 100,
                  spacingX,
                  spacingY,
                  diagonal,
              }
            : type === "text" && content?.trim()
            ? {
                  type: "text" as const,
                  content: resolvedContent,
                  fontSize: fontSize ?? 24,
                  fontFamily: fontFamily ?? "Sans Serif",
                  color: color ?? "#ffffff",
                  bold: bold ?? false,
                  italic: italic ?? false,
                  rotation: rotation ?? 0,
                  opacity: opacity ?? 100,
                  sizePct: size ?? 20,
                  spacingX,
                  spacingY,
                  diagonal,
              }
            : null
        : null;

    const tileDataUrl = useTilePreview(
        tileOpts,
        containerSize.w,
        containerSize.h,
    );

    const isText = menuKey === "text";
    const showSingleText = !isTiled && isText && !!content?.trim();
    const showSingleImage = !isTiled && !isText && !!imageUrl;

    const tileOverlayStyle: React.CSSProperties = diagonal
        ? {
              position: "absolute",
              width: "250%",
              height: "250%",
              top: "50%",
              left: "50%",
              transform: "translate(-50%, -50%) rotate(45deg)",
              backgroundImage: `url(${tileDataUrl})`,
              backgroundRepeat: "repeat",
              pointerEvents: "none",
          }
        : {
              position: "absolute",
              inset: 0,
              backgroundImage: `url(${tileDataUrl})`,
              backgroundRepeat: "repeat",
              pointerEvents: "none",
          };

    const positionLabel = POSITION_LABELS[position as WatermarkPosition] ?? "";

    return (
        <BlockStack
            gap={20}
            style={{
                width: "50%",
                position: "sticky",
                top: 0,
            }}
        >
            <SettingsField title={__("Preview", "ninja-media")}>
                <Card
                    background="white"
                    rounded="md"
                    style={{
                        position: "relative",
                        width: "100%",
                        height: "260px",
                        overflow: "hidden",
                        backgroundImage:
                            "linear-gradient(45deg, #f0f0f0 25%, transparent 25%), " +
                            "linear-gradient(-45deg, #f0f0f0 25%, transparent 25%), " +
                            "linear-gradient(45deg, transparent 75%, #f0f0f0 75%), " +
                            "linear-gradient(-45deg, transparent 75%, #f0f0f0 75%)",
                        backgroundSize: "20px 20px",
                        backgroundPosition:
                            "0 0, 0 10px, 10px -10px, -10px 0px",
                    }}
                >
                    <div
                        ref={containerRef}
                        style={{
                            position: "absolute",
                            inset: 0,
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                        }}
                    >
                        <Icon
                            color="descgray"
                            name="landscape"
                            style={{
                                fontSize: "80px",
                                opacity: 0.12,
                            }}
                        />
                    </div>

                    {isTiled && tileDataUrl && <div style={tileOverlayStyle} />}

                    {showSingleText && (
                        <span
                            style={textPreviewStyle({
                                fontSize,
                                fontFamily,
                                rotation,
                                color,
                                bold,
                                italic,
                                position,
                                opacity,
                                size,
                                edgeMargin,
                            })}
                        >
                            {resolvedContent}
                        </span>
                    )}

                    {showSingleImage && (
                        <img
                            src={imageUrl}
                            alt="preview"
                            style={{
                                ...positionStyle({
                                    position: position,
                                    size: size,
                                    edgeMargin: edgeMargin,
                                }),
                                opacity: (opacity as number) / 100,
                                pointerEvents: "none",
                            }}
                        />
                    )}

                    <div
                        style={{
                            position: "absolute",
                            top: "10px",
                            right: "10px",
                            background: "rgba(0,0,0,0.55)",
                            color: "#fff",
                            padding: "3px 8px",
                            borderRadius: "4px",
                            fontSize: "11px",
                            lineHeight: "16px",
                            pointerEvents: "none",
                        }}
                    >
                        {positionLabel} · {opacity}% · {size}%
                        {isTiled ? ` · ${__("Tiled", "ninja-media")}` : ""}
                    </div>
                </Card>
            </SettingsField>

            <Adjust />
        </BlockStack>
    );
};

export default Preview;

const positionStyle = ({
    position,
    size,
    edgeMargin,
}: {
    position?: WatermarkPosition;
    size?: number;
    edgeMargin?: number;
}): React.CSSProperties => {
    const margin = `${edgeMargin}px`;

    const base: React.CSSProperties = {
        position: "absolute",
        maxWidth: `${size}%`,
        maxHeight: `${size}%`,
        objectFit: "contain",
        transition: "all 0.25s ease",
    };

    if (position?.startsWith("top")) base.top = margin;
    else if (position?.startsWith("bottom")) base.bottom = margin;
    else {
        base.top = "50%";
        base.transform = "translateY(-50%)";
    }

    if (position?.endsWith("left")) base.left = margin;
    else if (position?.endsWith("right")) base.right = margin;
    else {
        base.left = "50%";
        base.transform = base.transform
            ? "translate(-50%, -50%)"
            : "translateX(-50%)";
    }

    return base;
};

const textPreviewStyle = ({
    fontSize,
    fontFamily,
    rotation,
    color,
    bold,
    italic,
    position,
    opacity,
    size,
    edgeMargin,
}: {
    fontSize?: number;
    fontFamily?: string;
    rotation?: number;
    color?: string;
    bold?: boolean;
    italic?: boolean;
    position?: WatermarkPosition;
    opacity?: number;
    size?: number;
    edgeMargin?: number;
}): React.CSSProperties => ({
    ...positionStyle({
        position,
        size,
        edgeMargin,
    }),
    fontSize: `${Math.max(8, Math.round((fontSize! * size!) / 100))}px`,
    fontFamily: fontFamily,
    transform: `${
        positionStyle({ position, size, edgeMargin }).transform ?? ""
    } rotate(${-rotation!}deg)`.trim(),
    color,
    fontWeight: bold ? "bold" : "normal",
    fontStyle: italic ? "italic" : "normal",
    opacity: (opacity! as number) / 100,
    whiteSpace: "nowrap",
    pointerEvents: "none",
    lineHeight: 1.2,
});

const POSITION_LABELS: Record<WatermarkPosition, string> = {
    "top-left": __("Top Left", "ninja-media"),
    "top-center": __("Top Center", "ninja-media"),
    "top-right": __("Top Right", "ninja-media"),
    "center-left": __("Center Left", "ninja-media"),
    center: __("Center", "ninja-media"),
    "center-right": __("Center Right", "ninja-media"),
    "bottom-left": __("Bottom Left", "ninja-media"),
    "bottom-center": __("Bottom Center", "ninja-media"),
    "bottom-right": __("Bottom Right", "ninja-media"),
};
