import { useCustomAlert } from "~/components/alert/Alert";
import { Settings } from "~/types/settings/settings";
import useSettings from "~/hooks/useSettings";

const useWatermarkActions = () => {
    const { data, setSettings, saveSettings } = useSettings();

    const { showAlert } = useCustomAlert();

    const resetSettings = () => {
        showAlert({
            type: "error",
            title: "Reset",
            text: `Are you sure you want to reset the watermark settings?`,
            showCancelButton: true,
            confirmButtonText: "Reset",
            onConfirm: async () => {
                setSettings(
                    "watermark",
                    pnpnm?.defaultSettings?.watermark || {},
                );

                const updatedSettings = {
                    ...data,
                    watermark: pnpnm?.defaultSettings?.watermark || {},
                } as Settings;

                await saveSettings(updatedSettings);
            },
        });
    };

    return { resetSettings };
};

export default useWatermarkActions;
